func Test_AnthropicToolCalling(t *testing.T) {
	// Chat request to Anthropic provider with a tool definition; assistant responds with a tool call
	var request pkg.ChatCompletionRequest
	if err := json.Unmarshal([]byte(`{"max_tokens":256,"messages":[{"content":"What is the weather in London?","role":"user"}],"model":"anthropic/claude-3-5-sonnet-20241022","tool_choice":"auto","tools":[{"function":{"description":"Get the current weather for a given location","name":"get_weather","parameters":{"properties":{"location":{"description":"The city and country, e.g. London, UK","type":"string"},"unit":{"description":"The temperature unit to use","enum":["celsius","fahrenheit"],"type":"string"}},"required":["location"],"type":"object"}},"type":"function"}]}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/anthropic_tool_calling"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Chat(request)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var choices0FinishReason string
	if result.Choices[0].FinishReason != nil {
		choices0FinishReason = string(*result.Choices[0].FinishReason)
	}
	assert.Equal(t, len(result.Choices), 1, "expected exactly 1 elements")
	if len(result.Choices) > 0 {
		if result.Choices[0].Message.ToolCalls == nil || len(result.Choices[0].Message.ToolCalls) == 0 {
			t.Errorf("expected non-empty value")
		}
	}
	if len(result.Choices) > 0 {
		if strings.TrimSpace(string(result.Choices[0].Message.ToolCalls[0].Function.Name)) != `get_weather` {
			t.Errorf("equals mismatch: got %v", result.Choices[0].Message.ToolCalls[0].Function.Name)
		}
	}
	if strings.TrimSpace(string(choices0FinishReason)) != `tool_calls` {
		t.Errorf("equals mismatch: got %v", choices0FinishReason)
	}
}

